deployment.program:
import credits.aleo;

program veilsub_social_v1.aleo;

record DMAccessProof:
    owner as address.private;
    creator as address.private;
    creator_hash as field.private;
    tier as u8.private;
    expires_at as u32.private;

record MessageReceipt:
    owner as address.private;
    message_hash as field.private;
    counterparty_hash as field.private;
    timestamp as u32.private;
    amount as u64.private;

record ChatMembership:
    owner as address.private;
    creator as address.private;
    room_id as u8.private;
    min_tier as u8.private;
    joined_at as u32.private;

record StoryAccess:
    owner as address.private;
    creator as address.private;
    story_id as field.private;
    expires_at as u32.private;
    encryption_key as field.private;

struct ChatRoomKey:
    creator_hash as field;
    room_id as u8;

struct StoryKey:
    creator_hash as field;
    story_id as field;

mapping dm_enabled:
    key as field.public;
    value as boolean.public;

mapping dm_price:
    key as field.public;
    value as u64.public;

mapping dm_min_tier:
    key as field.public;
    value as u8.public;

mapping dm_count:
    key as field.public;
    value as u64.public;

mapping chat_room_exists:
    key as field.public;
    value as boolean.public;

mapping chat_room_min_tier:
    key as field.public;
    value as u8.public;

mapping chat_member_count:
    key as field.public;
    value as u64.public;

mapping story_exists:
    key as field.public;
    value as boolean.public;

mapping story_expiry:
    key as field.public;
    value as u32.public;

mapping story_view_count:
    key as field.public;
    value as u64.public;

mapping creator_story_count:
    key as field.public;
    value as u64.public;

function configure_dm:
    input r0 as field.public;
    input r1 as u64.public;
    input r2 as u8.public;
    async configure_dm r0 r1 r2 into r3;
    output r3 as veilsub_social_v1.aleo/configure_dm.future;

finalize configure_dm:
    input r0 as field.public;
    input r1 as u64.public;
    input r2 as u8.public;
    set true into dm_enabled[r0];
    set r1 into dm_price[r0];
    set r2 into dm_min_tier[r0];

function prove_dm_access:
    input r0 as address.private;
    input r1 as u8.private;
    input r2 as u32.private;
    input r3 as field.private;
    gte r1 1u8 into r4;
    assert.eq r4 true;
    hash.psd2 r0 into r5 as field;
    cast self.caller r0 r5 r1 r2 into r6 as DMAccessProof.record;
    output r6 as DMAccessProof.record;

function send_paid_message:
    input r0 as DMAccessProof.record;
    input r1 as field.private;
    input r2 as credits.aleo/credits.record;
    input r3 as u64.private;
    assert.eq self.caller r0.owner;
    hash.psd2 self.caller into r4 as field;
    call credits.aleo/transfer_private r2 r0.creator r3 into r5 r6;
    cast self.caller r1 r0.creator_hash 0u32 r3 into r7 as MessageReceipt.record;
    cast r0.creator r1 r4 0u32 r3 into r8 as MessageReceipt.record;
    async send_paid_message r0.creator_hash into r9;
    output r7 as MessageReceipt.record;
    output r8 as MessageReceipt.record;
    output r5 as credits.aleo/credits.record;
    output r9 as veilsub_social_v1.aleo/send_paid_message.future;

finalize send_paid_message:
    input r0 as field.public;
    get.or_use dm_count[r0] 0u64 into r1;
    add r1 1u64 into r2;
    set r2 into dm_count[r0];

function create_chat_room:
    input r0 as field.public;
    input r1 as u8.public;
    input r2 as u8.public;
    async create_chat_room r0 r1 r2 into r3;
    output r3 as veilsub_social_v1.aleo/create_chat_room.future;

finalize create_chat_room:
    input r0 as field.public;
    input r1 as u8.public;
    input r2 as u8.public;
    cast r0 r1 into r3 as ChatRoomKey;
    hash.psd2 r3 into r4 as field;
    get.or_use chat_room_exists[r4] false into r5;
    not r5 into r6;
    assert.eq r6 true;
    set true into chat_room_exists[r4];
    set r2 into chat_room_min_tier[r4];
    set 0u64 into chat_member_count[r4];

function join_chat_room:
    input r0 as address.private;
    input r1 as u8.private;
    input r2 as u8.private;
    input r3 as u32.private;
    gte r2 1u8 into r4;
    assert.eq r4 true;
    hash.psd2 r0 into r5 as field;
    cast r5 r1 into r6 as ChatRoomKey;
    hash.psd2 r6 into r7 as field;
    cast self.caller r0 r1 r2 0u32 into r8 as ChatMembership.record;
    async join_chat_room r7 r2 into r9;
    output r8 as ChatMembership.record;
    output r9 as veilsub_social_v1.aleo/join_chat_room.future;

finalize join_chat_room:
    input r0 as field.public;
    input r1 as u8.public;
    get.or_use chat_room_exists[r0] false into r2;
    assert.eq r2 true;
    get.or_use chat_room_min_tier[r0] 1u8 into r3;
    gte r1 r3 into r4;
    assert.eq r4 true;
    get.or_use chat_member_count[r0] 0u64 into r5;
    add r5 1u64 into r6;
    set r6 into chat_member_count[r0];

function publish_story:
    input r0 as field.public;
    input r1 as field.public;
    input r2 as field.public;
    input r3 as u32.public;
    input r4 as field.private;
    gt r3 0u32 into r5;
    assert.eq r5 true;
    lte r3 28800u32 into r6;
    assert.eq r6 true;
    async publish_story r0 r1 r2 r3 into r7;
    output r7 as veilsub_social_v1.aleo/publish_story.future;

finalize publish_story:
    input r0 as field.public;
    input r1 as field.public;
    input r2 as field.public;
    input r3 as u32.public;
    cast r0 r1 into r4 as StoryKey;
    hash.psd2 r4 into r5 as field;
    get.or_use story_exists[r5] false into r6;
    not r6 into r7;
    assert.eq r7 true;
    set true into story_exists[r5];
    add block.height r3 into r8;
    set r8 into story_expiry[r5];
    set 0u64 into story_view_count[r5];
    get.or_use creator_story_count[r0] 0u64 into r9;
    add r9 1u64 into r10;
    set r10 into creator_story_count[r0];

function view_story:
    input r0 as address.private;
    input r1 as field.private;
    input r2 as u8.private;
    gte r2 1u8 into r3;
    assert.eq r3 true;
    hash.psd2 r0 into r4 as field;
    cast r4 r1 into r5 as StoryKey;
    hash.psd2 r5 into r6 as field;
    add r1 r4 into r7;
    hash.psd2 r7 into r8 as field;
    cast self.caller r0 r1 0u32 r8 into r9 as StoryAccess.record;
    async view_story r6 into r10;
    output r9 as StoryAccess.record;
    output r10 as veilsub_social_v1.aleo/view_story.future;

finalize view_story:
    input r0 as field.public;
    get.or_use story_exists[r0] false into r1;
    assert.eq r1 true;
    get.or_use story_expiry[r0] 0u32 into r2;
    lt block.height r2 into r3;
    assert.eq r3 true;
    get.or_use story_view_count[r0] 0u64 into r4;
    add r4 1u64 into r5;
    set r5 into story_view_count[r0];
